   169→static STACK_OF(X509_NAME) *
   170→tlso_ca_list( char * bundle, char * dir, X509 *cert )
   171→{
   172→	STACK_OF(X509_NAME) *ca_list = NULL;
   173→
   174→	if ( bundle ) {
   175→		ca_list = SSL_load_client_CA_file( bundle );
   176→	}
   177→	if ( dir ) {
   178→		char **dirs = ldap_str2charray( dir, CERTPATHSEP );
   179→		int freeit = 0, i, success = 0;
   180→
   181→		if ( !ca_list ) {
   182→			ca_list = sk_X509_NAME_new_null();
   183→			freeit = 1;
   184→		}
   185→		for ( i=0; dirs[i]; i++ ) {
   186→			success += SSL_add_dir_cert_subjects_to_stack( ca_list, dir );
   187→		}
   188→		if ( !success && freeit ) {
   189→			sk_X509_NAME_free( ca_list );
   190→			ca_list = NULL;
   191→		}
   192→		ldap_charray_free( dirs );
   193→	}
   194→	if ( cert ) {
   195→		X509_NAME *xn = X509_get_subject_name( cert );
   196→		xn = X509_NAME_dup( xn );
   197→		if ( !ca_list )
   198→			ca_list = sk_X509_NAME_new_null();
   199→		if ( xn && ca_list )
   200→			sk_X509_NAME_push( ca_list, xn );
   201→	}
   202→	return ca_list;
   203→}
