   284→#if OPENSSL_VERSION_NUMBER >= 0x10101000
   285→static char *
   286→tlso_stecpy( char *dst, const char *src, const char *end )
   287→{
   288→	while ( dst < end && *src )
   289→		*dst++ = *src++;
   290→	if ( dst < end )
   291→		*dst = '\0';
   292→	return dst;
   293→}
