   295→/* OpenSSL 1.1.1 uses a separate API for TLS1.3 ciphersuites.
   296→ * Try to find any TLS1.3 ciphers in the given list of suites.
   297→ */
   298→static void
   299→tlso_ctx_cipher13( tlso_ctx *ctx, char *suites )
   300→{
   301→	char tls13_suites[1024], *ts = tls13_suites, *te = tls13_suites + sizeof(tls13_suites);
   302→	char *ptr, *colon, *nptr;
   303→	char sname[128];
   304→	STACK_OF(SSL_CIPHER) *cs;
   305→	SSL *s = SSL_new( ctx );
   306→	int ret;
   307→
   308→	if ( !s )
   309→		return;
   310→
   311→	*ts = '\0';
   312→
   313→	/* check individual suites in a separate SSL handle before
   314→	 * mucking with the provided ctx. Init it to a known
   315→	 * mostly-empty state.
   316→	 */
   317→	SSL_set_ciphersuites( s, "" );
   318→	SSL_set_cipher_list( s, SSL3_TXT_RSA_NULL_SHA );
   319→
   320→	for ( ptr = suites;; ) {
   321→		colon = strchr( ptr, ':' );
   322→		if ( colon ) {
   323→			int len = colon - ptr;
   324→			if ( len > 63 ) len = 63;
   325→			strncpy( sname, ptr, len );
   326→			sname[len] = '\0';
   327→			nptr = sname;
   328→		} else {
   329→			nptr = ptr;
   330→		}
   331→		if ( SSL_set_ciphersuites( s, nptr )) {
   332→			cs = SSL_get_ciphers( s );
   333→			if ( cs ) {
   334→				const char *ver = SSL_CIPHER_get_version( sk_SSL_CIPHER_value( cs, 0 ));
   335→				if ( !strncmp( ver, "TLSv", 4 ) && strncmp( ver+4, "1.3", 3 ) >= 0 ) {
   336→					if ( tls13_suites[0] )
   337→						ts = tlso_stecpy( ts, ":", te );
   338→					ts = tlso_stecpy( ts, sname, te );
   339→				}
   340→			}
   341→		}
   342→		if ( !colon || ts >= te )
   343→			break;
   344→		ptr = colon+1;
   345→	}
   346→	SSL_free( s );
   347→
   348→	/* If no TLS1.3 ciphersuites were specified, leave current settings untouched. */
   349→	if ( tls13_suites[0] )
   350→		SSL_CTX_set_ciphersuites( ctx, tls13_suites );
   351→}
   352→#endif /* OpenSSL 1.1.1 */
