   354→/*
   355→ * initialize a new TLS context
   356→ */
   357→static int
   358→tlso_ctx_init( struct ldapoptions *lo, struct ldaptls *lt, int is_server, char *errmsg )
   359→{
   360→	tlso_ctx *ctx = (tlso_ctx *)lo->ldo_tls_ctx;
   361→	int i;
   362→
   363→	if ( is_server ) {
   364→		SSL_CTX_set_session_id_context( ctx,
   365→			(const unsigned char *) "OpenLDAP", sizeof("OpenLDAP")-1 );
   366→	}
   367→
   368→	if ( lo->ldo_tls_protocol_min ) {
   369→		int opt = 0;
   370→		if ( lo->ldo_tls_protocol_min > LDAP_OPT_X_TLS_PROTOCOL_SSL2 ) {
   371→			opt |= SSL_OP_NO_SSLv2;
   372→			SSL_CTX_clear_options( ctx, SSL_OP_NO_SSLv3 );
   373→		}
   374→		if ( lo->ldo_tls_protocol_min > LDAP_OPT_X_TLS_PROTOCOL_SSL3 )
   375→			opt |= SSL_OP_NO_SSLv3;
   376→#ifdef SSL_OP_NO_TLSv1
   377→		if ( lo->ldo_tls_protocol_min > LDAP_OPT_X_TLS_PROTOCOL_TLS1_0 )
   378→			opt |= SSL_OP_NO_TLSv1;
   379→#endif
   380→#ifdef SSL_OP_NO_TLSv1_1
   381→		if ( lo->ldo_tls_protocol_min > LDAP_OPT_X_TLS_PROTOCOL_TLS1_1 )
   382→			opt |= SSL_OP_NO_TLSv1_1;
   383→#endif
   384→#ifdef SSL_OP_NO_TLSv1_2
   385→		if ( lo->ldo_tls_protocol_min > LDAP_OPT_X_TLS_PROTOCOL_TLS1_2 )
   386→			opt |= SSL_OP_NO_TLSv1_2;
   387→#endif
   388→#ifdef SSL_OP_NO_TLSv1_3
   389→		if ( lo->ldo_tls_protocol_min > LDAP_OPT_X_TLS_PROTOCOL_TLS1_3 )
   390→			opt |= SSL_OP_NO_TLSv1_3;
   391→#endif
   392→		if ( opt )
   393→			SSL_CTX_set_options( ctx, opt );
   394→	}
   395→	if ( lo->ldo_tls_protocol_max ) {
   396→		int opt = 0;
   397→#ifdef SSL_OP_NO_TLSv1_3
   398→		if ( lo->ldo_tls_protocol_max < LDAP_OPT_X_TLS_PROTOCOL_TLS1_3 )
   399→			opt |= SSL_OP_NO_TLSv1_3;
   400→#endif
   401→#ifdef SSL_OP_NO_TLSv1_2
   402→		if ( lo->ldo_tls_protocol_max < LDAP_OPT_X_TLS_PROTOCOL_TLS1_2 )
   403→			opt |= SSL_OP_NO_TLSv1_2;
   404→#endif
   405→#ifdef SSL_OP_NO_TLSv1_1
   406→		if ( lo->ldo_tls_protocol_max < LDAP_OPT_X_TLS_PROTOCOL_TLS1_1 )
   407→			opt |= SSL_OP_NO_TLSv1_1;
   408→#endif
   409→#ifdef SSL_OP_NO_TLSv1
   410→		if ( lo->ldo_tls_protocol_max < LDAP_OPT_X_TLS_PROTOCOL_TLS1_0 )
   411→			opt |= SSL_OP_NO_TLSv1;
   412→#endif
   413→		if ( lo->ldo_tls_protocol_max < LDAP_OPT_X_TLS_PROTOCOL_SSL3 )
   414→			opt |= SSL_OP_NO_SSLv3;
   415→		if ( opt )
   416→			SSL_CTX_set_options( ctx, opt );
   417→	}
   418→
   419→	if ( lo->ldo_tls_ciphersuite ) {
   420→#if OPENSSL_VERSION_NUMBER >= 0x10101000
   421→		tlso_ctx_cipher13( ctx, lt->lt_ciphersuite );
   422→#endif
   423→		if ( !SSL_CTX_set_cipher_list( ctx, lt->lt_ciphersuite ) )
   424→		{
   425→			Debug1( LDAP_DEBUG_ANY,
   426→				   "TLS: could not set cipher list %s.\n",
   427→				   lo->ldo_tls_ciphersuite );
   428→			tlso_report_error( errmsg );
   429→			return -1;
   430→		}
   431→	}
   432→
   433→	if ( lo->ldo_tls_cacertfile == NULL && lo->ldo_tls_cacertdir == NULL &&
   434→		lo->ldo_tls_cacert.bv_val == NULL ) {
   435→		if ( !SSL_CTX_set_default_verify_paths( ctx ) ) {
   436→			Debug0( LDAP_DEBUG_ANY, "TLS: "
   437→				"could not use default certificate paths" );
   438→			tlso_report_error( errmsg );
   439→			return -1;
   440→		}
   441→	} else {
   442→		X509 *cert = NULL;
   443→		if ( lo->ldo_tls_cacert.bv_val ) {
   444→			const unsigned char *pp = (const unsigned char *) (lo->ldo_tls_cacert.bv_val);
   445→			cert = d2i_X509( NULL, &pp, lo->ldo_tls_cacert.bv_len );
   446→			X509_STORE *store = SSL_CTX_get_cert_store( ctx );
   447→			if ( !X509_STORE_add_cert( store, cert )) {
   448→				Debug0( LDAP_DEBUG_ANY, "TLS: "
   449→					"could not use CA certificate" );
   450→				tlso_report_error( errmsg );
   451→				return -1;
   452→			}
   453→		}
   454→		if ( lt->lt_cacertfile || lt->lt_cacertdir ) {
   455→			char **dirs, *dummy = NULL;
   456→			if ( lt->lt_cacertdir ) {
   457→				dirs = ldap_str2charray( lt->lt_cacertdir, CERTPATHSEP );
   458→			} else {
   459→				dirs = &dummy;
   460→			}
   461→			/* Start with the first dir in path */
   462→			if ( !SSL_CTX_load_verify_locations( ctx,
   463→				lt->lt_cacertfile, dirs[0] ) )
   464→			{
   465→				Debug2( LDAP_DEBUG_ANY, "TLS: "
   466→					"could not load verify locations (file:`%s',dir:`%s').\n",
   467→					lo->ldo_tls_cacertfile ? lo->ldo_tls_cacertfile : "",
   468→					dirs[0] ? dirs[0] : "" );
   469→				tlso_report_error( errmsg );
   470→				if ( dirs != &dummy )
   471→					ldap_charray_free( dirs );
   472→				return -1;
   473→			}
   474→			/* Then additional dirs, if any */
   475→			if ( dirs != &dummy ) {
   476→				if ( dirs[1] ) {
   477→					int i;
   478→					X509_STORE *store = SSL_CTX_get_cert_store( ctx );
   479→					X509_LOOKUP *lookup = X509_STORE_add_lookup( store, X509_LOOKUP_hash_dir() );
   480→					for ( i=1; dirs[i]; i++ )
   481→						X509_LOOKUP_add_dir( lookup, dirs[i], X509_FILETYPE_PEM );
   482→				}
   483→				ldap_charray_free( dirs );
   484→			}
   485→		}
   486→
   487→		if ( is_server ) {
   488→			STACK_OF(X509_NAME) *calist;
   489→			/* List of CA names to send to a client */
   490→			calist = tlso_ca_list( lt->lt_cacertfile, lt->lt_cacertdir, cert );
   491→			if ( !calist ) {
   492→				Debug2( LDAP_DEBUG_ANY, "TLS: "
   493→					"could not load client CA list (file:`%s',dir:`%s').\n",
   494→					lo->ldo_tls_cacertfile ? lo->ldo_tls_cacertfile : "",
   495→					lo->ldo_tls_cacertdir ? lo->ldo_tls_cacertdir : "" );
   496→				tlso_report_error( errmsg );
   497→				return -1;
   498→			}
   499→
   500→			SSL_CTX_set_client_CA_list( ctx, calist );
   501→		}
   502→		if ( cert )
   503→			X509_free( cert );
   504→	}
   505→
   506→	if ( lo->ldo_tls_cert.bv_val )
   507→	{
   508→		const unsigned char *pp = (const unsigned char *) (lo->ldo_tls_cert.bv_val);
   509→		X509 *cert = d2i_X509( NULL, &pp, lo->ldo_tls_cert.bv_len );
   510→		if ( !SSL_CTX_use_certificate( ctx, cert )) {
   511→			Debug0( LDAP_DEBUG_ANY,
   512→				"TLS: could not use certificate.\n" );
   513→			tlso_report_error( errmsg );
   514→			return -1;
   515→		}
   516→		X509_free( cert );
   517→	} else
   518→	if ( lo->ldo_tls_certfile &&
   519→		!SSL_CTX_use_certificate_chain_file( ctx, lt->lt_certfile) )
   520→	{
   521→		Debug1( LDAP_DEBUG_ANY,
   522→			"TLS: could not use certificate file `%s'.\n",
   523→			lo->ldo_tls_certfile );
   524→		tlso_report_error( errmsg );
   525→		return -1;
   526→	}
   527→
   528→	/* Key validity is checked automatically if cert has already been set */
   529→	if ( lo->ldo_tls_key.bv_val )
   530→	{
   531→		const unsigned char *pp = (const unsigned char *) (lo->ldo_tls_key.bv_val);
   532→		EVP_PKEY *pkey = d2i_AutoPrivateKey( NULL, &pp, lo->ldo_tls_key.bv_len );
   533→		if ( !SSL_CTX_use_PrivateKey( ctx, pkey ))
   534→		{
   535→			Debug0( LDAP_DEBUG_ANY,
   536→				"TLS: could not use private key.\n" );
   537→			tlso_report_error( errmsg );
   538→			return -1;
   539→		}
   540→		EVP_PKEY_free( pkey );
   541→	} else
   542→	if ( lo->ldo_tls_keyfile &&
   543→		!SSL_CTX_use_PrivateKey_file( ctx,
   544→			lt->lt_keyfile, SSL_FILETYPE_PEM ) )
   545→	{
   546→		Debug1( LDAP_DEBUG_ANY,
   547→			"TLS: could not use key file `%s'.\n",
   548→			lo->ldo_tls_keyfile );
   549→		tlso_report_error( errmsg );
   550→		return -1;
   551→	}
   552→
   553→	if ( is_server && lo->ldo_tls_dhfile ) {
   554→#if OPENSSL_VERSION_MAJOR >= 3
   555→		EVP_PKEY *dh;
   556→#define	bio_params( bio, dh )	dh = PEM_read_bio_Parameters( bio, &dh )
   557→#else
   558→		DH *dh;
   559→#define	bio_params( bio, dh )	dh = PEM_read_bio_DHparams( bio, NULL, NULL, NULL )
   560→#endif
   561→		BIO *bio;
   562→
   563→		if (( bio=BIO_new_file( lt->lt_dhfile,"r" )) == NULL ) {
   564→			Debug1( LDAP_DEBUG_ANY,
   565→				"TLS: could not use DH parameters file `%s'.\n",
   566→				lo->ldo_tls_dhfile );
   567→			tlso_report_error( errmsg );
   568→			return -1;
   569→		}
   570→		if (!( bio_params( bio, dh ))) {
   571→			Debug1( LDAP_DEBUG_ANY,
   572→				"TLS: could not read DH parameters file `%s'.\n",
   573→				lo->ldo_tls_dhfile );
   574→			tlso_report_error( errmsg );
   575→			BIO_free( bio );
   576→			return -1;
   577→		}
   578→		BIO_free( bio );
   579→#if OPENSSL_VERSION_MAJOR >= 3
   580→		SSL_CTX_set0_tmp_dh_pkey( ctx, dh );
   581→#else
   582→		SSL_CTX_set_tmp_dh( ctx, dh );
   583→		SSL_CTX_set_options( ctx, SSL_OP_SINGLE_DH_USE );
   584→		DH_free( dh );
   585→#endif
   586→	}
   587→
   588→	if ( lo->ldo_tls_ecname ) {
   589→#ifdef OPENSSL_NO_EC
   590→		Debug0( LDAP_DEBUG_ANY,
   591→			"TLS: Elliptic Curves not supported.\n" );
   592→		return -1;
   593→#else
   594→		if ( !SSL_CTX_set1_curves_list( ctx, lt->lt_ecname )) {
   595→			Debug1( LDAP_DEBUG_ANY,
   596→				"TLS: could not set EC name `%s'.\n",
   597→				lo->ldo_tls_ecname );
   598→			tlso_report_error( errmsg );
   599→			return -1;
   600→		}
   601→	/*
   602→	 * This is a NOP in OpenSSL 1.1.0 and later, where curves are always
   603→	 * auto-negotiated.
   604→	 */
   605→#if OPENSSL_VERSION_NUMBER < 0x10100000UL
   606→		if ( SSL_CTX_set_ecdh_auto( ctx, 1 ) <= 0 ) {
   607→			Debug0( LDAP_DEBUG_ANY,
   608→				"TLS: could not enable automatic EC negotiation.\n" );
   609→		}
   610→#endif
   611→#endif	/* OPENSSL_NO_EC */
   612→	}
   613→
   614→	if ( tlso_opt_trace ) {
   615→		SSL_CTX_set_info_callback( ctx, tlso_info_cb );
   616→	}
   617→
   618→	i = SSL_VERIFY_NONE;
   619→	if ( lo->ldo_tls_require_cert ) {
   620→		i = SSL_VERIFY_PEER;
   621→		if ( lo->ldo_tls_require_cert == LDAP_OPT_X_TLS_DEMAND ||
   622→			 lo->ldo_tls_require_cert == LDAP_OPT_X_TLS_HARD ) {
   623→			i |= SSL_VERIFY_FAIL_IF_NO_PEER_CERT;
   624→		}
   625→	}
   626→
   627→	SSL_CTX_set_verify( ctx, i,
   628→		lo->ldo_tls_require_cert == LDAP_OPT_X_TLS_ALLOW ?
   629→		tlso_verify_ok : tlso_verify_cb );
   630→#if OPENSSL_VERSION_NUMBER < 0x10100000
   631→	SSL_CTX_set_tmp_rsa_callback( ctx, tlso_tmp_rsa_cb );
   632→#endif
   633→	if ( lo->ldo_tls_crlcheck ) {
   634→		X509_STORE *x509_s = SSL_CTX_get_cert_store( ctx );
   635→		if ( lo->ldo_tls_crlcheck == LDAP_OPT_X_TLS_CRL_PEER ) {
   636→			X509_STORE_set_flags( x509_s, X509_V_FLAG_CRL_CHECK );
   637→		} else if ( lo->ldo_tls_crlcheck == LDAP_OPT_X_TLS_CRL_ALL ) {
   638→			X509_STORE_set_flags( x509_s, 
   639→					X509_V_FLAG_CRL_CHECK | X509_V_FLAG_CRL_CHECK_ALL  );
   640→		}
   641→	}
   642→	/* Explicitly honor the server side cipher suite preference */
   643→	SSL_CTX_set_options( ctx, SSL_OP_CIPHER_SERVER_PREFERENCE );
   644→	return 0;
   645→}
