   681→static int
   682→tlso_session_upflags( Sockbuf *sb, tls_session *sess, int rc )
   683→{
   684→	tlso_session *s = (tlso_session *)sess;
   685→
   686→	/* 1 was subtracted above, offset it back now */
   687→	rc = SSL_get_error(s, rc+1);
   688→	if (rc == SSL_ERROR_WANT_READ) {
   689→		sb->sb_trans_needs_read  = 1;
   690→		return 1;
   691→
   692→	} else if (rc == SSL_ERROR_WANT_WRITE) {
   693→		sb->sb_trans_needs_write = 1;
   694→		return 1;
   695→
   696→	} else if (rc == SSL_ERROR_WANT_CONNECT) {
   697→		return 1;
   698→	}
   699→	return 0;
   700→}
