   703→tlso_session_errmsg( tls_session *sess, int rc, char *buf, size_t len )
   704→{
   705→	char err[256] = "";
   706→	const char *certerr=NULL;
   707→	tlso_session *s = (tlso_session *)sess;
   708→
   709→	rc = ERR_peek_error();
   710→	if ( rc ) {
   711→		ERR_error_string_n( rc, err, sizeof(err) );
   712→		if ( ( ERR_GET_LIB(rc) == ERR_LIB_SSL ) && 
   713→				( ERR_GET_REASON(rc) == SSL_R_CERTIFICATE_VERIFY_FAILED ) ) {
   714→			int certrc = SSL_get_verify_result(s);
   715→			certerr = (char *)X509_verify_cert_error_string(certrc);
