   786→
   787→/* what kind of hostname were we given? */
   788→#define	IS_DNS	0
   789→#define	IS_IP4	1
   790→#define	IS_IP6	2
   791→
   792→static int
   793→tlso_session_chkhost( LDAP *ld, tls_session *sess, const char *name_in )
   794→{
   795→	tlso_session *s = (tlso_session *)sess;
   796→	int i, ret = LDAP_LOCAL_ERROR;
   797→	int chkSAN = ld->ld_options.ldo_tls_require_san, gotSAN = 0;
   798→	X509 *x;
   799→	const char *name;
   800→	char *ptr;
   801→	int ntype = IS_DNS, nlen;
   802→#ifdef LDAP_PF_INET6
   803→	struct in6_addr addr;
   804→#else
   805→	struct in_addr addr;
   806→#endif
   807→
   808→	if( ldap_int_hostname &&
   809→		( !name_in || !strcasecmp( name_in, "localhost" ) ) )
   810→	{
   811→		name = ldap_int_hostname;
   812→	} else {
   813→		name = name_in;
   814→	}
   815→	nlen = strlen(name);
   816→
   817→	x = tlso_get_cert(s);
   818→	if (!x) {
   819→		Debug0( LDAP_DEBUG_ANY,
   820→			"TLS: unable to get peer certificate.\n" );
   821→		/* If this was a fatal condition, things would have
   822→		 * aborted long before now.
   823→		 */
   824→		return LDAP_SUCCESS;
   825→	}
   826→
   827→#ifdef LDAP_PF_INET6
   828→	if (inet_pton(AF_INET6, name, &addr)) {
   829→		ntype = IS_IP6;
   830→	} else 
   831→#endif
   832→	if ((ptr = strrchr(name, '.')) && isdigit((unsigned char)ptr[1])) {
   833→		if (inet_aton(name, (struct in_addr *)&addr)) ntype = IS_IP4;
   834→	}
   835→
   836→	if (chkSAN) {
   837→	i = X509_get_ext_by_NID(x, NID_subject_alt_name, -1);
   838→	if (i >= 0) {
   839→		X509_EXTENSION *ex;
   840→		STACK_OF(GENERAL_NAME) *alt;
   841→
   842→		ex = X509_get_ext(x, i);
   843→		alt = X509V3_EXT_d2i(ex);
   844→		if (alt) {
   845→			int n, len2 = 0;
   846→			char *domain = NULL;
   847→			GENERAL_NAME *gn;
   848→
   849→			gotSAN = 1;
   850→			if (ntype == IS_DNS) {
   851→				domain = strchr(name, '.');
   852→				if (domain) {
   853→					len2 = nlen - (domain-name);
   854→				}
   855→			}
   856→			n = sk_GENERAL_NAME_num(alt);
   857→			for (i=0; i<n; i++) {
   858→				char *sn;
   859→				int sl;
   860→				gn = sk_GENERAL_NAME_value(alt, i);
   861→				if (gn->type == GEN_DNS) {
   862→					if (ntype != IS_DNS) continue;
   863→
   864→					sn = (char *) ASN1_STRING_data(gn->d.ia5);
   865→					sl = ASN1_STRING_length(gn->d.ia5);
   866→
   867→					/* ignore empty */
   868→					if (sl == 0) continue;
   869→
   870→					/* Is this an exact match? */
   871→					if ((nlen == sl) && !strncasecmp(name, sn, nlen)) {
   872→						break;
   873→					}
   874→
   875→					/* Is this a wildcard match? */
   876→					if (domain && (sn[0] == '*') && (sn[1] == '.') &&
   877→						(len2 == sl-1) && !strncasecmp(domain, &sn[1], len2))
   878→					{
   879→						break;
   880→					}
   881→
   882→				} else if (gn->type == GEN_IPADD) {
   883→					if (ntype == IS_DNS) continue;
   884→
   885→					sn = (char *) ASN1_STRING_data(gn->d.ia5);
   886→					sl = ASN1_STRING_length(gn->d.ia5);
   887→
   888→#ifdef LDAP_PF_INET6
   889→					if (ntype == IS_IP6 && sl != sizeof(struct in6_addr)) {
   890→						continue;
   891→					} else
   892→#endif
   893→					if (ntype == IS_IP4 && sl != sizeof(struct in_addr)) {
   894→						continue;
   895→					}
   896→					if (!memcmp(sn, &addr, sl)) {
   897→						break;
   898→					}
   899→				}
   900→			}
   901→
   902→			GENERAL_NAMES_free(alt);
   903→			if (i < n) {	/* Found a match */
   904→				ret = LDAP_SUCCESS;
   905→			}
   906→		}
   907→	}
   908→	}
   909→	if (ret != LDAP_SUCCESS && chkSAN) {
   910→		switch(chkSAN) {
   911→		case LDAP_OPT_X_TLS_DEMAND:
   912→		case LDAP_OPT_X_TLS_HARD:
   913→			if (!gotSAN) {
   914→				Debug0( LDAP_DEBUG_ANY,
   915→					"TLS: unable to get subjectAltName from peer certificate.\n" );
   916→				ret = LDAP_CONNECT_ERROR;
   917→				if ( ld->ld_error ) {
   918→					LDAP_FREE( ld->ld_error );
   919→				}
   920→				ld->ld_error = LDAP_STRDUP(
   921→					_("TLS: unable to get subjectAltName from peer certificate"));
   922→				goto done;
   923→			}
   924→			/* FALLTHRU */
   925→		case LDAP_OPT_X_TLS_TRY:
   926→			if (gotSAN) {
   927→				Debug1( LDAP_DEBUG_ANY, "TLS: hostname (%s) does not match "
   928→					"subjectAltName in certificate.\n",
   929→					name );
   930→				ret = LDAP_CONNECT_ERROR;
   931→				if ( ld->ld_error ) {
   932→					LDAP_FREE( ld->ld_error );
   933→				}
   934→				ld->ld_error = LDAP_STRDUP(
   935→					_("TLS: hostname does not match subjectAltName in peer certificate"));
   936→				goto done;
   937→			}
   938→			break;
   939→		case LDAP_OPT_X_TLS_ALLOW:
   940→			break;
   941→		}
   942→	}
   943→
   944→	if (ret != LDAP_SUCCESS) {
   945→		X509_NAME *xn;
   946→		X509_NAME_ENTRY *ne;
   947→		ASN1_OBJECT *obj;
   948→		ASN1_STRING *cn = NULL;
   949→		int navas;
   950→
   951→		/* find the last CN */
   952→		obj = OBJ_nid2obj( NID_commonName );
   953→		if ( !obj ) goto no_cn;	/* should never happen */
   954→
   955→		xn = X509_get_subject_name(x);
   956→		navas = X509_NAME_entry_count( xn );
   957→		for ( i=navas-1; i>=0; i-- ) {
   958→			ne = X509_NAME_get_entry( xn, i );
   959→			if ( !OBJ_cmp( X509_NAME_ENTRY_get_object(ne), obj )) {
   960→				cn = X509_NAME_ENTRY_get_data( ne );
   961→				break;
   962→			}
   963→		}
   964→
   965→		if( !cn )
   966→		{
   967→no_cn:
   968→			Debug0( LDAP_DEBUG_ANY,
   969→				"TLS: unable to get common name from peer certificate.\n" );
   970→			ret = LDAP_CONNECT_ERROR;
   971→			if ( ld->ld_error ) {
   972→				LDAP_FREE( ld->ld_error );
   973→			}
   974→			ld->ld_error = LDAP_STRDUP(
   975→				_("TLS: unable to get CN from peer certificate"));
   976→
   977→		} else if ( cn->length == nlen &&
   978→			strncasecmp( name, (char *) cn->data, nlen ) == 0 ) {
   979→			ret = LDAP_SUCCESS;
   980→
   981→		} else if (( cn->data[0] == '*' ) && ( cn->data[1] == '.' )) {
   982→			char *domain = strchr(name, '.');
   983→			if( domain ) {
   984→				int dlen;
   985→
   986→				dlen = nlen - (domain-name);
   987→
   988→				/* Is this a wildcard match? */
   989→				if ((dlen == cn->length-1) &&
   990→					!strncasecmp(domain, (char *) &cn->data[1], dlen)) {
   991→					ret = LDAP_SUCCESS;
   992→				}
   993→			}
   994→		}
   995→
   996→		if( ret == LDAP_LOCAL_ERROR ) {
   997→			Debug3( LDAP_DEBUG_ANY, "TLS: hostname (%s) does not match "
   998→				"common name in certificate (%.*s).\n", 
   999→				name, cn->length, cn->data );
  1000→			ret = LDAP_CONNECT_ERROR;
  1001→			if ( ld->ld_error ) {
  1002→				LDAP_FREE( ld->ld_error );
  1003→			}
  1004→			ld->ld_error = LDAP_STRDUP(
  1005→				_("TLS: hostname does not match name in peer certificate"));
  1006→		}
  1007→	}
  1008→done:
  1009→	X509_free(x);
  1010→	return ret;
  1011→}
