  1013→static int
  1014→tlso_session_strength( tls_session *sess )
  1015→{
  1016→	tlso_session *s = (tlso_session *)sess;
  1017→
  1018→	return SSL_CIPHER_get_bits(SSL_get_current_cipher(s), NULL);
  1019→}
