  1021→static int
  1022→tlso_session_unique( tls_session *sess, struct berval *buf, int is_server)
  1023→{
  1024→	tlso_session *s = (tlso_session *)sess;
  1025→
  1026→	/* Usually the client sends the finished msg. But if the
  1027→	 * session was resumed, the server sent the msg.
  1028→	 */
  1029→	if (SSL_session_reused(s) ^ !is_server)
  1030→		buf->bv_len = SSL_get_finished(s, buf->bv_val, buf->bv_len);
  1031→	else
  1032→		buf->bv_len = SSL_get_peer_finished(s, buf->bv_val, buf->bv_len);
  1033→	return buf->bv_len;
  1034→}
  1035→
  1036→static int
  1037→tlso_session_endpoint( tls_session *sess, struct berval *buf, int is_server )
  1038→{
  1039→	tlso_session *s = (tlso_session *)sess;
  1040→	const EVP_MD *md;
  1041→	unsigned int md_len;
  1042→	X509 *cert;
  1043→
  1044→	if ( buf->bv_len < EVP_MAX_MD_SIZE )
  1045→		return 0;
  1046→
  1047→	if ( is_server )
  1048→		cert = SSL_get_certificate( s );
  1049→	else
  1050→		cert = SSL_get_peer_certificate( s );
  1051→
  1052→	if ( cert == NULL )
  1053→		return 0;
  1054→
  1055→#if OPENSSL_VERSION_NUMBER >= 0x10100000
  1056→	md = EVP_get_digestbynid( X509_get_signature_nid( cert ));
  1057→#else
  1058→	md = EVP_get_digestbynid(OBJ_obj2nid( cert->sig_alg->algorithm ));
  1059→#endif
  1060→
  1061→	/* See RFC 5929 */
  1062→	if ( md == NULL ||
  1063→	     md == EVP_md_null() ||
  1064→#ifndef OPENSSL_NO_MD2
  1065→	     md == EVP_md2() ||
  1066→#endif
  1067→#ifndef OPENSSL_NO_MD4
  1068→	     md == EVP_md4() ||
  1069→#endif
  1070→#ifndef OPENSSL_NO_MD5
  1071→	     md == EVP_md5() ||
  1072→#endif
  1073→	     md == EVP_sha1() )
  1074→		md = EVP_sha256();
  1075→
  1076→	if ( !X509_digest( cert, md, (unsigned char *) (buf->bv_val), &md_len ))
  1077→		md_len = 0;
  1078→
  1079→	buf->bv_len = md_len;
  1080→	if ( !is_server )
  1081→		X509_free( cert );
  1082→
  1083→	return md_len;
  1084→}
