  1100→static int
  1101→tlso_session_peercert( tls_session *sess, struct berval *der )
  1102→{
  1103→	tlso_session *s = (tlso_session *)sess;
  1104→	int ret = -1;
  1105→	X509 *x = SSL_get_peer_certificate(s);
  1106→	if ( x ) {
  1107→		der->bv_len = i2d_X509(x, NULL);
  1108→		der->bv_val = LDAP_MALLOC(der->bv_len);
  1109→		if ( der->bv_val ) {
  1110→			unsigned char *ptr = (unsigned char *) (der->bv_val);
  1111→			i2d_X509(x, &ptr);
  1112→			ret = 0;
  1113→		}
  1114→		X509_free( x );
  1115→	}
  1116→	return ret;
  1117→}
  1118→
  1119→static int
  1120→tlso_session_pinning( LDAP *ld, tls_session *sess, char *hashalg, struct berval *hash )
  1121→{
  1122→	tlso_session *s = (tlso_session *)sess;
  1123→	unsigned char *tmp, digest[EVP_MAX_MD_SIZE];
  1124→	struct berval key,
  1125→				  keyhash = { sizeof(digest), (char *) digest };
  1126→	X509 *cert = SSL_get_peer_certificate(s);
  1127→	int len, rc = LDAP_SUCCESS;
  1128→
  1129→	if ( !cert )
  1130→		return -1;
  1131→
  1132→	len = i2d_X509_PUBKEY( X509_get_X509_PUBKEY(cert), NULL );
  1133→
  1134→	tmp = LDAP_MALLOC( len );
  1135→	key.bv_val = (char *) tmp;
  1136→
  1137→	if ( !key.bv_val ) {
  1138→		rc = -1;
  1139→		goto done;
  1140→	}
  1141→
  1142→	key.bv_len = i2d_X509_PUBKEY( X509_get_X509_PUBKEY(cert), &tmp );
  1143→
  1144→	if ( hashalg ) {
  1145→		const EVP_MD *md;
  1146→		EVP_MD_CTX *mdctx;
  1147→		unsigned int len = keyhash.bv_len;
  1148→
  1149→		md = EVP_get_digestbyname( hashalg );
  1150→		if ( !md ) {
  1151→			Debug1( LDAP_DEBUG_TRACE, "tlso_session_pinning: "
  1152→					"hash %s not recognised by OpenSSL\n", hashalg );
  1153→			rc = -1;
  1154→			goto done;
  1155→		}
  1156→
  1157→#if OPENSSL_VERSION_NUMBER >= 0x10100000
  1158→		mdctx = EVP_MD_CTX_new();
  1159→#else
  1160→		mdctx = EVP_MD_CTX_create();
  1161→#endif
  1162→		if ( !mdctx ) {
  1163→			rc = -1;
  1164→			goto done;
  1165→		}
  1166→
  1167→		EVP_DigestInit_ex( mdctx, md, NULL );
  1168→		EVP_DigestUpdate( mdctx, key.bv_val, key.bv_len );
  1169→		EVP_DigestFinal_ex( mdctx, (unsigned char *)keyhash.bv_val, &len );
  1170→		keyhash.bv_len = len;
  1171→#if OPENSSL_VERSION_NUMBER >= 0x10100000
  1172→		EVP_MD_CTX_free( mdctx );
  1173→#else
  1174→		EVP_MD_CTX_destroy( mdctx );
  1175→#endif
  1176→	} else {
  1177→		keyhash = key;
  1178→	}
  1179→
  1180→	if ( ber_bvcmp( hash, &keyhash ) ) {
  1181→		rc = LDAP_CONNECT_ERROR;
  1182→		Debug0( LDAP_DEBUG_ANY, "tlso_session_pinning: "
  1183→				"public key hash does not match provided pin.\n" );
  1184→		if ( ld->ld_error ) {
  1185→			LDAP_FREE( ld->ld_error );
  1186→		}
  1187→		ld->ld_error = LDAP_STRDUP(
  1188→			_("TLS: public key hash does not match provided pin"));
  1189→	}
  1190→
  1191→done:
  1192→	LDAP_FREE( key.bv_val );
  1193→	X509_free( cert );
  1194→	return rc;
  1195→}
