  1206→#if OPENSSL_VERSION_NUMBER < 0x10100000
  1207→#define BIO_set_init(b, x)	b->init = x
  1208→#define BIO_set_data(b, x)	b->ptr = x
  1209→#define BIO_clear_flags(b, x)	b->flags &= ~(x)
