  1231→static int
  1232→tlso_bio_read( BIO *b, char *buf, int len )
  1233→{
  1234→	struct tls_data		*p;
  1235→	int			ret;
  1236→		
  1237→	if ( buf == NULL || len <= 0 ) return 0;
  1238→
  1239→	p = (struct tls_data *)BIO_get_data(b);
  1240→
  1241→	if ( p == NULL || p->sbiod == NULL ) {
  1242→		return 0;
  1243→	}
  1244→
  1245→	ret = LBER_SBIOD_READ_NEXT( p->sbiod, buf, len );
  1246→
  1247→	BIO_clear_retry_flags( b );
  1248→	if ( ret < 0 ) {
  1249→		int err = sock_errno();
  1250→		if ( err == EAGAIN || err == EWOULDBLOCK ) {
  1251→			BIO_set_retry_read( b );
  1252→		}
  1253→	}
  1254→
  1255→	return ret;
  1256→}
