  1396→static ber_slen_t
  1397→tlso_sb_read( Sockbuf_IO_Desc *sbiod, void *buf, ber_len_t len)
  1398→{
  1399→	struct tls_data		*p;
  1400→	ber_slen_t		ret;
  1401→	int			err;
  1402→
  1403→	assert( sbiod != NULL );
  1404→	assert( SOCKBUF_VALID( sbiod->sbiod_sb ) );
  1405→
  1406→	p = (struct tls_data *)sbiod->sbiod_pvt;
  1407→
  1408→	ret = SSL_read( p->session, (char *)buf, len );
  1409→#ifdef HAVE_WINSOCK
  1410→	errno = WSAGetLastError();
  1411→#endif
  1412→	err = SSL_get_error( p->session, ret );
  1413→	if (err == SSL_ERROR_WANT_READ ) {
  1414→		sbiod->sbiod_sb->sb_trans_needs_read = 1;
  1415→		sock_errset(EWOULDBLOCK);
  1416→	}
  1417→	else
  1418→		sbiod->sbiod_sb->sb_trans_needs_read = 0;
  1419→	return ret;
  1420→}
