  1429→	assert( sbiod != NULL );
  1430→	assert( SOCKBUF_VALID( sbiod->sbiod_sb ) );
  1431→
  1432→	p = (struct tls_data *)sbiod->sbiod_pvt;
  1433→
  1434→	ret = SSL_write( p->session, (char *)buf, len );
