  1439→	if (err == SSL_ERROR_WANT_WRITE ) {
  1440→		sbiod->sbiod_sb->sb_trans_needs_write = 1;
  1441→		sock_errset(EWOULDBLOCK);
  1442→
  1443→	} else {
