  1459→/* Derived from openssl/apps/s_cb.c */
  1460→static void
  1461→tlso_info_cb( const SSL *ssl, int where, int ret )
  1462→{
  1463→	int w;
  1464→	char *op;
  1465→	char *state = (char *) SSL_state_string_long( (SSL *)ssl );
  1466→
  1467→	w = where & ~SSL_ST_MASK;
  1468→	if ( w & SSL_ST_CONNECT ) {
  1469→		op = "SSL_connect";
  1470→	} else if ( w & SSL_ST_ACCEPT ) {
  1471→		op = "SSL_accept";
  1472→	} else {
  1473→		op = "undefined";
  1474→	}
  1475→
  1476→#ifdef HAVE_EBCDIC
  1477→	if ( state ) {
  1478→		state = LDAP_STRDUP( state );
  1479→		__etoa( state );
  1480→	}
  1481→#endif
  1482→	if ( where & SSL_CB_LOOP ) {
  1483→		Debug2( LDAP_DEBUG_TRACE,
  1484→			   "TLS trace: %s:%s\n",
  1485→			   op, state );
  1486→
  1487→	} else if ( where & SSL_CB_ALERT ) {
  1488→		char *atype = (char *) SSL_alert_type_string_long( ret );
  1489→		char *adesc = (char *) SSL_alert_desc_string_long( ret );
  1490→		op = ( where & SSL_CB_READ ) ? "read" : "write";
  1491→#ifdef HAVE_EBCDIC
  1492→		if ( atype ) {
  1493→			atype = LDAP_STRDUP( atype );
  1494→			__etoa( atype );
  1495→		}
  1496→		if ( adesc ) {
  1497→			adesc = LDAP_STRDUP( adesc );
  1498→			__etoa( adesc );
  1499→		}
  1500→#endif
  1501→		Debug3( LDAP_DEBUG_TRACE,
  1502→			   "TLS trace: SSL3 alert %s:%s:%s\n",
  1503→			   op, atype, adesc );
  1504→#ifdef HAVE_EBCDIC
  1505→		if ( atype ) LDAP_FREE( atype );
  1506→		if ( adesc ) LDAP_FREE( adesc );
  1507→#endif
  1508→	} else if ( where & SSL_CB_EXIT ) {
  1509→		if ( ret == 0 ) {
  1510→			Debug2( LDAP_DEBUG_TRACE,
  1511→				   "TLS trace: %s:failed in %s\n",
  1512→				   op, state );
  1513→		} else if ( ret < 0 ) {
  1514→			Debug2( LDAP_DEBUG_TRACE,
  1515→				   "TLS trace: %s:error in %s\n",
  1516→				   op, state );
  1517→		}
  1518→	}
  1519→#ifdef HAVE_EBCDIC
  1520→	if ( state ) LDAP_FREE( state );
  1521→#endif
  1522→}
