  1524→static int
  1525→tlso_verify_cb( int ok, X509_STORE_CTX *ctx )
  1526→{
  1527→	X509 *cert;
  1528→	int errnum;
  1529→	int errdepth;
  1530→	X509_NAME *subject;
  1531→	X509_NAME *issuer;
  1532→	char *sname;
  1533→	char *iname;
  1534→	char *certerr = NULL;
  1535→
  1536→	cert = X509_STORE_CTX_get_current_cert( ctx );
  1537→	errnum = X509_STORE_CTX_get_error( ctx );
  1538→	errdepth = X509_STORE_CTX_get_error_depth( ctx );
  1539→
  1540→	/*
  1541→	 * X509_get_*_name return pointers to the internal copies of
  1542→	 * those things requested.  So do not free them.
  1543→	 */
  1544→	subject = X509_get_subject_name( cert );
  1545→	issuer = X509_get_issuer_name( cert );
  1546→	/* X509_NAME_oneline, if passed a NULL buf, allocate memory */
  1547→	sname = X509_NAME_oneline( subject, NULL, 0 );
  1548→	iname = X509_NAME_oneline( issuer, NULL, 0 );
  1549→	if ( !ok ) certerr = (char *)X509_verify_cert_error_string( errnum );
  1550→#ifdef HAVE_EBCDIC
  1551→	if ( sname ) __etoa( sname );
  1552→	if ( iname ) __etoa( iname );
  1553→	if ( certerr ) {
  1554→		certerr = LDAP_STRDUP( certerr );
  1555→		__etoa( certerr );
  1556→	}
  1557→#endif
  1558→	Debug3( LDAP_DEBUG_TRACE,
  1559→		   "TLS certificate verification: depth: %d, err: %d, subject: %s,",
  1560→		   errdepth, errnum,
  1561→		   sname ? sname : "-unknown-" );
  1562→	Debug1( LDAP_DEBUG_TRACE, " issuer: %s\n", iname ? iname : "-unknown-" );
  1563→	if ( !ok ) {
  1564→		Debug1( LDAP_DEBUG_ANY,
  1565→			"TLS certificate verification: Error, %s\n",
  1566→			certerr );
  1567→	}
  1568→	if ( sname )
  1569→		OPENSSL_free ( sname );
  1570→	if ( iname )
  1571→		OPENSSL_free ( iname );
  1572→#ifdef HAVE_EBCDIC
  1573→	if ( certerr ) LDAP_FREE( certerr );
  1574→#endif
  1575→	return ok;
  1576→}
  1577→
  1578→static int
  1579→tlso_verify_ok( int ok, X509_STORE_CTX *ctx )
  1580→{
  1581→	(void) tlso_verify_cb( ok, ctx );
  1582→	return 1;
  1583→}
