  1585→/* Inspired by ERR_print_errors in OpenSSL */
  1586→static void
  1587→tlso_report_error( char *errmsg )
  1588→{
  1589→	unsigned long l;
  1590→	char buf[ERRBUFSIZE];
  1591→	const char *file;
  1592→	int line;
  1593→
  1594→	while ( ( l = ERR_get_error_line( &file, &line ) ) != 0 ) {
  1595→		ERR_error_string_n( l, buf, ERRBUFSIZE );
  1596→		if ( !*errmsg )
  1597→			strcpy(errmsg, buf );
  1598→#ifdef HAVE_EBCDIC
  1599→		if ( file ) {
  1600→			file = LDAP_STRDUP( file );
  1601→			__etoa( (char *)file );
  1602→		}
  1603→		__etoa( buf );
  1604→#endif
  1605→		Debug3( LDAP_DEBUG_ANY, "TLS: %s %s:%d\n",
  1606→			buf, file, line );
  1607→#ifdef HAVE_EBCDIC
  1608→		if ( file ) LDAP_FREE( (void *)file );
  1609→#endif
  1610→	}
  1611→}
