  1613→#if OPENSSL_VERSION_NUMBER < 0x10100000
  1614→static RSA *
  1615→tlso_tmp_rsa_cb( SSL *ssl, int is_export, int key_length )
  1616→{
  1617→	RSA *tmp_rsa;
  1618→	/* FIXME:  Pregenerate the key on startup */
  1619→	/* FIXME:  Who frees the key? */
  1620→	BIGNUM *bn = BN_new();
  1621→	tmp_rsa = NULL;
  1622→	if ( bn ) {
  1623→		if ( BN_set_word( bn, RSA_F4 )) {
  1624→			tmp_rsa = RSA_new();
  1625→			if ( tmp_rsa && !RSA_generate_key_ex( tmp_rsa, key_length, bn, NULL )) {
  1626→				RSA_free( tmp_rsa );
  1627→				tmp_rsa = NULL;
  1628→			}
  1629→		}
  1630→		BN_free( bn );
  1631→	}
  1632→
  1633→	if ( !tmp_rsa ) {
  1634→		Debug2( LDAP_DEBUG_ANY,
  1635→			"TLS: Failed to generate temporary %d-bit %s RSA key\n",
  1636→			key_length, is_export ? "export" : "domestic" );
  1637→	}
  1638→	return tmp_rsa;
  1639→}
  1640→#endif /* OPENSSL_VERSION_NUMBER < 1.1 */
  1641→
  1642→static int
  1643→tlso_seed_PRNG( const char *randfile )
  1644→{
  1645→#ifndef URANDOM_DEVICE
  1646→	/* no /dev/urandom (or equiv) */
  1647→	long total=0;
  1648→	char buffer[MAXPATHLEN];
  1649→
  1650→	if (randfile == NULL) {
  1651→		/* The seed file is $RANDFILE if defined, otherwise $HOME/.rnd.
  1652→		 * If $HOME is not set or buffer too small to hold the pathname,
  1653→		 * an error occurs.	- From RAND_file_name() man page.
  1654→		 * The fact is that when $HOME is NULL, .rnd is used.
  1655→		 */
  1656→		randfile = RAND_file_name( buffer, sizeof( buffer ) );
  1657→	}
  1658→#ifndef OPENSSL_NO_EGD
  1659→	else if (RAND_egd(randfile) > 0) {
  1660→		/* EGD socket */
  1661→		return 0;
  1662→	}
  1663→#endif
  1664→
  1665→	if (randfile == NULL) {
  1666→		Debug0( LDAP_DEBUG_ANY,
  1667→			"TLS: Use configuration file or $RANDFILE to define seed PRNG\n" );
  1668→		return -1;
  1669→	}
  1670→
  1671→	total = RAND_load_file(randfile, -1);
  1672→
  1673→	if (RAND_status() == 0) {
  1674→		Debug0( LDAP_DEBUG_ANY,
  1675→			"TLS: PRNG not been seeded with enough data\n" );
  1676→		return -1;
  1677→	}
  1678→
  1679→	/* assume if there was enough bits to seed that it's okay
  1680→	 * to write derived bits to the file
  1681→	 */
  1682→	RAND_write_file(randfile);
  1683→
  1684→#endif
  1685→
  1686→	return 0;
  1687→}
